import React from 'react';
import clsx from 'clsx';
import { useCssScope } from '../config-provider/hooks';
import TimelineItem from './TimelineItem';
import type { TimelineType } from './types';
import { getDefaultSizeAbbr } from '../util';
import { Loading } from '../loading';

import './style';

const useTimelineCssScope = () => useCssScope('timeline');
const useTimelineItemCssScope = () => useCssScope('timeline-item');

const Timeline: TimelineType = props => {
  const {
    mode = 'left',
    reverse,
    hangingTail,
    children,
    pending,
    pendingDot,
    space = 'medium',
    style,
    className,
    labelPosition = 'relative',
    ...restProps
  } = props;
  const timelineItems = React.Children.toArray(children);
  const validTimelineItems = timelineItems.filter(item => React.isValidElement(item)) as React.ReactElement[];
  const hasLabel = validTimelineItems.some(item => Boolean(item?.props?.label));
  const cssScope = useTimelineCssScope();
  const itemCssScope = useTimelineItemCssScope();

  const items = React.Children.map(validTimelineItems, (item: React.ReactElement, index) =>
    React.cloneElement(item, {
      className: clsx(
        mode === 'alternate'
          ? itemCssScope(`--mode-alt-${index % 2 === 0 ? 'left' : 'right'}`)
          : itemCssScope(`--mode-${mode}`),
        {
          [itemCssScope('-last')]: pending && !reverse && index === validTimelineItems.length - 1,
        },
        item.props.className,
      ),
      key: index,
      labelPosition,
    }),
  );

  if (pending) {
    const pendingNode = (
      <TimelineItem
        status="current"
        className={clsx(
          mode === 'alternate' ? itemCssScope('--mode-alt-left') : itemCssScope(`--mode-${mode}`),
          itemCssScope('--pending'),
        )}
        key="pending"
        dot={pendingDot || <Loading className={itemCssScope('--loading')} />}
        title={typeof pending === 'boolean' ? null : pending}
        labelPosition={labelPosition}
      />
    );

    items.push(pendingNode);
  }

  if (reverse) {
    items.reverse();
  }

  return (
    <ul
      style={style}
      {...restProps}
      className={clsx(
        cssScope(),
        {
          [cssScope('--no-label')]: !hasLabel,
          [cssScope('__hanging-tail')]: hangingTail,
          [cssScope('-pending')]: pending,
        },
        cssScope(`--space-${getDefaultSizeAbbr(space, 'medium')}`),
        className,
      )}
    >
      {items}
    </ul>
  );
};

Timeline.Item = TimelineItem;

if (__DEV__) {
  Timeline.displayName = 'Timeline';
}

export default Timeline;
